import React, { useState, useEffect, createContext, useContext } from 'react';
import { createRoot } from 'react-dom/client';

const OIDC_CONFIG = {
  authority: 'https://your-oidc-provider.com',
  client_id: 'your-client-id',
  redirect_uri: window.location.origin + '/callback',
  response_type: 'code',
  scope: 'openid profile email',
  post_logout_redirect_uri: window.location.origin
};

const AuthContext = createContext(null);

function generateRandomString(length) {
  const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  let result = '';
  const randomValues = new Uint8Array(length);
  crypto.getRandomValues(randomValues);
  for (let i = 0; i < length; i++) {
    result += charset[randomValues[i] % charset.length];
  }
  return result;
}

async function sha256(plain) {
  const encoder = new TextEncoder();
  const data = encoder.encode(plain);
  return await crypto.subtle.digest('SHA-256', data);
}

function base64UrlEncode(arrayBuffer) {
  const bytes = new Uint8Array(arrayBuffer);
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary)
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
}

function base64UrlDecode(str) {
  str = str.replace(/-/g, '+').replace(/_/g, '/');
  while (str.length % 4) {
    str += '=';
  }
  return atob(str);
}

function decodeJWT(token) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) {
      throw new Error('Invalid JWT format');
    }
    const payload = base64UrlDecode(parts[1]);
    return JSON.parse(payload);
  } catch (error) {
    console.error('Error decoding JWT:', error);
    return null;
  }
}

class OIDCClient {
  constructor(config) {
    this.config = config;
  }

  async login() {
    const state = generateRandomString(32);
    const codeVerifier = generateRandomString(64);
    const codeChallenge = base64UrlEncode(await sha256(codeVerifier));

    sessionStorage.setItem('oidc_state', state);
    sessionStorage.setItem('oidc_code_verifier', codeVerifier);

    const params = new URLSearchParams({
      client_id: this.config.client_id,
      redirect_uri: this.config.redirect_uri,
      response_type: this.config.response_type,
      scope: this.config.scope,
      state: state,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256'
    });

    const authUrl = `${this.config.authority}/authorize?${params.toString()}`;
    window.location.href = authUrl;
  }

  async handleCallback() {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');
    const error = urlParams.get('error');

    if (error) {
      throw new Error(`OIDC Error: ${error} - ${urlParams.get('error_description')}`);
    }

    const savedState = sessionStorage.getItem('oidc_state');
    if (state !== savedState) {
      throw new Error('State mismatch - possible CSRF attack');
    }

    const codeVerifier = sessionStorage.getItem('oidc_code_verifier');
    sessionStorage.removeItem('oidc_state');
    sessionStorage.removeItem('oidc_code_verifier');

    const tokens = await this.exchangeCodeForTokens(code, codeVerifier);
    return tokens;
  }

  async exchangeCodeForTokens(code, codeVerifier) {
    const params = new URLSearchParams({
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: this.config.redirect_uri,
      client_id: this.config.client_id,
      code_verifier: codeVerifier
    });

    const response = await fetch(`${this.config.authority}/token`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(`Token exchange failed: ${errorData.error_description || errorData.error}`);
    }

    const tokens = await response.json();
    return tokens;
  }

  async refreshToken(refreshToken) {
    const params = new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: this.config.client_id
    });

    const response = await fetch(`${this.config.authority}/token`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });

    if (!response.ok) {
      throw new Error('Token refresh failed');
    }

    const tokens = await response.json();
    return tokens;
  }

  logout() {
    const params = new URLSearchParams({
      client_id: this.config.client_id,
      post_logout_redirect_uri: this.config.post_logout_redirect_uri
    });

    const logoutUrl = `${this.config.authority}/logout?${params.toString()}`;
    window.location.href = logoutUrl;
  }
}

function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [tokens, setTokens] = useState(null);
  const oidcClient = new OIDCClient(OIDC_CONFIG);

  useEffect(() => {
    const initAuth = async () => {
      const storedTokens = localStorage.getItem('oidc_tokens');
      if (storedTokens) {
        try {
          const parsedTokens = JSON.parse(storedTokens);
          const idToken = decodeJWT(parsedTokens.id_token);
          
          if (idToken && idToken.exp * 1000 > Date.now()) {
            setTokens(parsedTokens);
            setUser(idToken);
          } else {
            localStorage.removeItem('oidc_tokens');
          }
        } catch (error) {
          console.error('Error loading stored tokens:', error);
          localStorage.removeItem('oidc_tokens');
        }
      }
      setLoading(false);
    };

    initAuth();
  }, []);

  const login = () => {
    oidcClient.login();
  };

  const logout = () => {
    localStorage.removeItem('oidc_tokens');
    setUser(null);
    setTokens(null);
    oidcClient.logout();
  };

  const handleTokens = (newTokens) => {
    const idToken = decodeJWT(newTokens.id_token);
    setTokens(newTokens);
    setUser(idToken);
    localStorage.setItem('oidc_tokens', JSON.stringify(newTokens));
  };

  const value = {
    user,
    tokens,
    loading,
    login,
    logout,
    isAuthenticated: !!user,
    handleTokens,
    oidcClient
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context;
}

function CallbackPage() {
  const { handleTokens, oidcClient } = useAuth();
  const [error, setError] = useState(null);

  useEffect(() => {
    const processCallback = async () => {
      try {
        const tokens = await oidcClient.handleCallback();
        handleTokens(tokens);
        window.history.replaceState({}, document.title, '/');
      } catch (err) {
        console.error('Callback error:', err);
        setError(err.message);
      }
    };

    processCallback();
  }, []);

  if (error) {
    return (
      <div style={{ padding: '20px', textAlign: 'center' }}>
        <h2>Authentication Error</h2>
        <p style={{ color: 'red' }}>{error}</p>
        <button onClick={() => window.location.href = '/'}>Go Home</button>
      </div>
    );
  }

  return (
    <div style={{ padding: '20px', textAlign: 'center' }}>
      <h2>Processing authentication...</h2>
      <p>Please wait while we complete your login.</p>
    </div>
  );
}

